import{_ as r,o as i,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"🫘 黃豆追蹤日報 — 2026-05-21（週四）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-21.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-21.md"}'),a={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-21.md"};function e(n,t,s,d,g,h){return i(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="🫘-黃豆追蹤日報-—-2026-05-21-週四" tabindex="-1">🫘 黃豆追蹤日報 — 2026-05-21（週四） <a class="header-anchor" href="#🫘-黃豆追蹤日報-—-2026-05-21-週四" aria-label="Permalink to &quot;🫘 黃豆追蹤日報 — 2026-05-21（週四）&quot;">​</a></h1><blockquote><p>查詢時間：2026-05-21 05:47 TST（2026-05-20 21:47 UTC） 報告類型：每日追蹤 ⚠️ CBOT 期貨時段說明：05:47 TST 週四凌晨 = 17:47 ET 週三，黃豆期貨已收盤</p></blockquote><hr><h2 id="📊-即時報價" tabindex="-1">📊 即時報價 <a class="header-anchor" href="#📊-即時報價" aria-label="Permalink to &quot;📊 即時報價&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>報價</th><th>日漲跌</th><th>查詢時間</th><th>來源</th></tr></thead><tbody><tr><td>CBOT 黃豆 Jul 2026 (ZSN26)</td><td>~1,202-1,204 USd/Bu</td><td>-5~7¢ (-0.4-0.6%)</td><td>2026-05-20 16:00 ET</td><td>Western Producer / Mysteel</td></tr><tr><td>WTI 原油</td><td>~$99-104/桶</td><td>—</td><td>2026-05-20</td><td>TradingEconomics</td></tr><tr><td>Brent 原油</td><td>$110.51/桶</td><td>—</td><td>2026-05-19</td><td>TradingEconomics</td></tr><tr><td>DXY 美元指數</td><td>99.11</td><td>-0.19%</td><td>2026-05-20</td><td>FXStreet</td></tr><tr><td>天然氣 Henry Hub</td><td>$2.96/MMBtu</td><td>—</td><td>2026-05-15</td><td>TradingEconomics</td></tr></tbody></table><blockquote><p><strong>查詢時間（TST）</strong>：2026-05-21 05:47</p></blockquote><hr><h2 id="🔍-敘事延續-川習會承諾持續消化-種植大幅領先-fomc-鷹派-—-黃豆續跌-5-7¢" tabindex="-1">🔍 敘事延續：川習會承諾持續消化 + 種植大幅領先 + FOMC 鷹派 — 黃豆續跌 5-7¢ <a class="header-anchor" href="#🔍-敘事延續-川習會承諾持續消化-種植大幅領先-fomc-鷹派-—-黃豆續跌-5-7¢" aria-label="Permalink to &quot;🔍 敘事延續：川習會承諾持續消化 + 種植大幅領先 + FOMC 鷹派 — 黃豆續跌 5-7¢&quot;">​</a></h2><p><strong>本日核心</strong>：CBOT 黃豆 Jul 週三續跌 5-7 美分/蒲式耳，延續昨日 -0.33% 跌幅。三重壓力持續：① 川習會 $17B 農業承諾利好已在週一反映，後續無新催化；② 巴西出口競爭激烈，全球供應充足；③ FOMC 鷹派 → 美元偏強 → 出口競爭力下降。但下行有支撐：USDA 種植進度大幅領先（67% vs 五年均值 53%），利空有限；油價高檔支撐能源成本邏輯。</p><hr><h2 id="_8-項追蹤指標" tabindex="-1">8 項追蹤指標 <a class="header-anchor" href="#_8-項追蹤指標" aria-label="Permalink to &quot;8 項追蹤指標&quot;">​</a></h2><h3 id="_1-usda-種植進度報告-每週" tabindex="-1">1. USDA 種植進度報告（每週） <a class="header-anchor" href="#_1-usda-種植進度報告-每週" aria-label="Permalink to &quot;1. USDA 種植進度報告（每週）&quot;">​</a></h3><ul><li><strong>種植進度</strong>（截至 5/18）：67% 黃豆已播種（前週 48%），高於五年均值 53%</li><li><strong>出芽率</strong>：32% 已出芽</li><li><strong>個別州</strong>： <ul><li>Iowa：60%（前週 60%）</li><li>Nebraska：64%（大幅領先）</li><li>Tennessee：76%（遠超均值）</li><li>Minnesota：51%（大幅領先）</li><li>Ohio：46%（vs 五年均值 35%）</li><li>Indiana：51%（大幅領先）</li><li>Michigan：12%（落後，異常低）</li></ul></li><li><strong>變化</strong>：🟢 <strong>大幅領先</strong> — 67% vs 53% 五年均值，Michigan 為唯一落後州</li><li><strong>分析</strong>：種植順利 → 供應預期增加 → 利空；但 Michigan 落後需關注</li><li><strong>查詢時間</strong>：2026-05-18</li><li>來源：Brownfield Ag News (2026-05-18)、RFD TV (2026-05-18)、OCJ (2026-05-19)</li></ul><h3 id="_2-巴西供應-收割-出口-豐收" tabindex="-1">2. 巴西供應（收割 + 出口 + 豐收） <a class="header-anchor" href="#_2-巴西供應-收割-出口-豐收" aria-label="Permalink to &quot;2. 巴西供應（收割 + 出口 + 豐收）&quot;">​</a></h3><ul><li><strong>CONAB</strong>（5 月）：2025/26 產量 180.13M 噸（+0.5% vs 前估，+5% YoY）</li><li><strong>StoneX</strong>（5 月）：下修至 177.8M 噸（南大河乾旱）</li><li><strong>出口</strong>：CONAB 預測 116M 噸（歷史新高，+7.25% YoY）</li><li><strong>2026/27 展望</strong>：USDA 預估巴西產量 186M 噸（+8M vs 本季）</li><li><strong>巴西農民困境</strong>：低黃豆價格 + 高生產成本 + 弱港口溢價 → 利潤壓縮 → 擴種放緩</li><li><strong>變化</strong>：🟡 無重大變化 — 本季已收割完成，關注下季播種</li><li><strong>查詢時間</strong>：2026-05-19</li><li>來源：CONAB (2026-05)、Caixin Global (2026-05-18)、Farmdocdaily (2026-03)</li></ul><h3 id="_3-尿素價格-多單訊號" tabindex="-1">3. 尿素價格 + 多單訊號 <a class="header-anchor" href="#_3-尿素價格-多單訊號" aria-label="Permalink to &quot;3. 尿素價格 + 多單訊號&quot;">​</a></h3><ul><li><strong>尿素</strong>：$577/噸（+0.79%），月跌 19.07% 但年漲 21.79%</li><li><strong>荷莫茲效應</strong>：全球 ~30% 化肥出口經過海峽，成本持續高檔</li><li><strong>變化</strong>：🟡 成本高檔但月跌 — 短期壓力紓解但長期結構性上升</li><li><strong>查詢時間</strong>：2026-05-15</li><li>來源：TradingEconomics (2026-05-15)</li></ul><h3 id="_4-荷莫茲海峽通航狀態" tabindex="-1">4. 荷莫茲海峽通航狀態 <a class="header-anchor" href="#_4-荷莫茲海峽通航狀態" aria-label="Permalink to &quot;4. 荷莫茲海峽通航狀態&quot;">​</a></h3><ul><li>🔴 <strong>持續封閉但談判進入「最後階段」</strong>：</li><li><strong>川普</strong>（5/20）：稱與伊朗談判處於「最後階段」，若失敗將發動攻擊</li><li><strong>IRGC</strong>：警告「若侵略重複，承諾的區域戰爭將超出中東」</li><li><strong>NATO 護航</strong>：部分北約國家支持 7 月初護航船隻通過海峽</li><li><strong>NYT 分析</strong>：伊朗使用「三角 coerción」策略——攻擊灣區國家 + 封鎖海峽</li><li><strong>海峽現狀</strong>：實質封閉未變，70+ 艘商業船被改道</li><li><strong>對黃豆影響</strong>：油價高檔 → 能源成本壓力持續 → 農業成本負擔</li><li><strong>變化</strong>：🟡 <strong>談判進入關鍵階段但未實質改善</strong> — 任何突破將大幅改變格局</li><li><strong>查詢時間</strong>：2026-05-20</li><li>來源：NYT (2026-05-20)、ISW (2026-05-19)、FXStreet (2026-05-20)</li></ul><h3 id="_5-中美貿易-中國進口" tabindex="-1">5. 中美貿易 + 中國進口 <a class="header-anchor" href="#_5-中美貿易-中國進口" aria-label="Permalink to &quot;5. 中美貿易 + 中國進口&quot;">​</a></h3><ul><li>🟡 <strong>承諾已公布但缺乏細節</strong>：</li><li><strong>White House</strong>（5/17）：中國承諾 2026-2028 每年購買 $17B 美國農產品</li><li><strong>額外承諾</strong>（2025/10）：中國承諾每年購買至少 25M 噸美國黃豆</li><li><strong>實際執行情況</strong>：1-3 月中國從美國進口 3.4M 噸黃豆，但後續採購尚未落實</li><li><strong>S&amp;P Global</strong>：年初至今美國對華黃豆銷售年減 48%</li><li><strong>分析</strong>：$17B 承諾 + 25M 噸年度目標是正面信號，但「preliminary」+ 缺乏細節 → 市場觀望</li><li><strong>變化</strong>：🟡 延續前次 — 承諾已公布但等待中國實際行動</li><li><strong>查詢時間</strong>：2026-05-20</li><li>來源：White House (2026-05)、SCMP (2026-05-16)、Caixin Global (2026-05-18)</li></ul><h3 id="_6-天然氣價格" tabindex="-1">6. 天然氣價格 <a class="header-anchor" href="#_6-天然氣價格" aria-label="Permalink to &quot;6. 天然氣價格&quot;">​</a></h3><ul><li><strong>Henry Hub</strong>：$2.96/MMBtu（+2.28%），接近七週高</li><li><strong>EIA 注入</strong>：85 bcf（符合預期），低於去年同期 109 bcf</li><li><strong>變化</strong>：🟡 無重大變化 — 供給偏緊但需求季節性低</li><li><strong>查詢時間</strong>：2026-05-15</li><li>來源：TradingEconomics (2026-05-15)</li></ul><h3 id="_7-聖嬰-拉尼娜氣候風險" tabindex="-1">7. 聖嬰/拉尼娜氣候風險 <a class="header-anchor" href="#_7-聖嬰-拉尼娜氣候風險" aria-label="Permalink to &quot;7. 聖嬰/拉尼娜氣候風險&quot;">​</a></h3><ul><li><strong>變化</strong>：⚪ 本日無重大更新 — 待下季氣候報告</li><li><strong>查詢時間</strong>：2026-05-21</li></ul><h3 id="_8-cbot-價格區間-海運成本" tabindex="-1">8. CBOT 價格區間 + 海運成本 <a class="header-anchor" href="#_8-cbot-價格區間-海運成本" aria-label="Permalink to &quot;8. CBOT 價格區間 + 海運成本&quot;">​</a></h3><ul><li><strong>Jul 2026</strong>：~1,202-1,204 USd/Bu（-5~7¢），從昨日 1,209 續跌</li><li><strong>技術面</strong>：支撐 1,180-1,200¢，壓力 1,220-1,240¢</li><li><strong>新作物 Nov</strong>：觸三年新高 &gt;$12/bu（受 WASDE 利多）</li><li><strong>跌因</strong>：① 川習會承諾利好消化後獲利了結；② 巴西出口競爭；③ FOMC 鷹派 → 美元偏強</li><li><strong>變化</strong>：🟡 <strong>連續兩日回調</strong> — 從週一高點 ~1,245 回落至 ~1,202，跌幅 ~3.5%</li><li><strong>查詢時間</strong>：2026-05-20</li><li>來源：Western Producer (2026-05-20)、Mysteel (2026-05-20)、Grain SA (2026-05-20)</li></ul><hr><h2 id="📰-即時新聞-5-條" tabindex="-1">📰 即時新聞（5 條） <a class="header-anchor" href="#📰-即時新聞-5-條" aria-label="Permalink to &quot;📰 即時新聞（5 條）&quot;">​</a></h2><ol><li><strong>Western Producer (2026-05-20)</strong>：CBOT soybeans trending 5-7 cents lower on Wednesday, soymeal slightly lower</li><li><strong>Mysteel (2026-05-20)</strong>：CBOT soybeans pulled back on profit-taking, Brazil competition</li><li><strong>Grain SA (2026-05-20)</strong>：CBOT soybean prices traded lower due to large South American supplies and improved US weather</li><li><strong>FXStreet (2026-05-20)</strong>：DXY slides to 99.11, but FOMC hawkish — dollar strength pressures exports</li><li><strong>BNN Bloomberg (2026-05-20)</strong>：Fed minutes hawkish — rate hike if inflation persists, 50% Dec probability</li></ol><hr><h2 id="📊-情景分析" tabindex="-1">📊 情景分析 <a class="header-anchor" href="#📊-情景分析" aria-label="Permalink to &quot;📊 情景分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>發生機率</th><th>價格影響</th><th>傳導機制</th></tr></thead><tbody><tr><td>伊朗和談成功 + 海峽重開 + 中國採購落實</td><td>20%</td><td>+8-12%（至 ~1,300-1,360¢）</td><td>能源成本暴跌 + 需求大增</td></tr><tr><td>海峽持續封閉 + 種植順利 + 中國觀望</td><td>50%</td><td>持平至 -2%（1,180-1,220¢）</td><td>供應充足 vs 能源成本高檔</td></tr><tr><td>FOMC 升息 + 美元大幅走強 + 中國延遲</td><td>30%</td><td>-3-5%（至 ~1,150-1,180¢）</td><td>出口競爭力下降 + 資金外流</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>Western Producer (2026-05-20): CBOT soybeans -5-7 cents, soymeal lower</li><li>Mysteel (2026-05-20): CBOT soybean futures pulled back on profit-taking</li><li>Grain SA (2026-05-20): Soybean prices lower on South American supplies</li><li>TradingEconomics (2026-05-19): Soybeans 1,209 (-0.33%)</li><li>Brownfield Ag News (2026-05-18): USDA crop progress 67% planted</li><li>RFD TV (2026-05-18): Soybean planting progress by state</li><li>CONAB (2026-05): Brazil soybean production 180.13M tons</li><li>BNN Bloomberg (2026-05-20): Fed minutes hawkish, rate hike likely</li><li>FXStreet (2026-05-20): DXY 99.11, gold rallies</li><li>White House (2026-05): China commits $17B/year in US ag purchases</li></ol>',36)])])}const b=r(a,[["render",e]]);export{c as __pageData,b as default};
